INSERT OR REPLACE INTO verses (id,work_id,division_id,ref,ordinal,devanagari,translit,uvaca,source_url) VALUES ('cb.adi.14.3','cb','cb.adi.14','ЧБ Ади 14.3',3,'জয় জয় সর্ব্ববৈষ্ণবের ধন-প্রাণ ।
কৃপা-দৃষ্ট্যে কর’, প্রভু, সর্ব্বজীবে ত্রাণ ॥৩॥','джайа джайа сарва-ваиш̣н̣авера дхана-пра̄н̣а
кр̣па̄-др̣ш̣т̣йе кара’, прабху, сарва-джӣве тра̄н̣а',NULL,NULL),('cb.adi.14.4','cb','cb.adi.14','ЧБ Ади 14.4',4,'আদিখণ্ডকথা, ভাই, শুন একমনে ।
বিপ্ররূপে কৃষ্ণ বিহরিলেন যেমনে ॥৪॥','а̄ди-кхан̣д̣а-катха̄, бха̄и ш́уне эка-мане
випра-рӯпе кр̣ш̣н̣а вихарилена йемане',NULL,NULL),('cb.adi.14.5','cb','cb.adi.14','ЧБ Ади 14.5',5,'হেনমতে বৈকুণ্ঠ-নায়ক সর্ব্বক্ষণ ।
বিদ্যা-রসে বিহরেন লই’ শিষ্যগণ ॥৫॥','хӣна-мате ваикун̣т̣ха-на̄йака сарва-кш̣ан̣а
видйа̄-расе вихарен̣а лаи’ ш́иш̣йа-ган̣а',NULL,NULL),('cb.adi.14.6','cb','cb.adi.14','ЧБ Ади 14.6',6,'সর্ব্ব-নবদ্বীপে প্রতি নগরে-নগরে ।
শিষ্যগণ-সঙ্গে বিদ্যারসে ক্রীড়া করে ॥৬॥','сарва-навадвӣпе прати-нагаре-нагаре
ш́иш̣йа-ган̣а-сан̇ге видйа̄-расе крӣд̣а̄ каре',NULL,NULL),('cb.adi.14.7','cb','cb.adi.14','ЧБ Ади 14.7',7,'সর্ব্ব-নবদ্বীপে সর্ব্বলোকে হৈল ধ্বনি ।
‘নিমাইপণ্ডিত অধ্যাপক-শিরোমণি’ ॥৭॥','сарва навадвӣпе сарва-локе хаила дхвани
‘нима̄и-пан̣д̣ита адхйа̄пака-ш́ироман̣и’',NULL,NULL),('cb.adi.14.8','cb','cb.adi.14','ЧБ Ади 14.8',8,'বড় বড় বিষয়ী সকল দোলা হৈতে ।
নামিয়া করেন নমস্কার বহুমতে ॥৮॥','бад̣а бад̣а виш̣айӣ сакала дола̄ хаите
на̄мийа̄ карена намаска̄ра баху-мате',NULL,NULL),('cb.adi.14.9','cb','cb.adi.14','ЧБ Ади 14.9',9,'প্রভু দেখি’ মাত্র জন্মে সবার সাধ্বস ।
নবদ্বীপে হেন নাহি,—যে না হয় বশ ॥৯॥','прабху декхи’ ма̄тра джанме саба̄ра са̄дхваса
навадвӣпе хӣна на̄хи, — йе на̄ хайа ваш́а',NULL,NULL),('cb.adi.14.10','cb','cb.adi.14','ЧБ Ади 14.10',10,'নবদ্বীপে যারা যত ধর্ম্ম-কর্ম্ম করে ।
ভোজ্য-বস্ত্র অবশ্য পাঠায় প্রভু-ঘরে ॥১০॥','навадвӣпе йа̄’ра̄ йата дхарма-карма каре
бходжйа-вастра аваш́йа па̄т̣ха̄йа прабху-гхаре',NULL,NULL),('cb.adi.14.11','cb','cb.adi.14','ЧБ Ади 14.11',11,'প্রভু সে পরম-ব্যয়ী ঈশ্বর-ব্যভার ।
দুঃখিতেরে নিরবধি দেন পুরস্কার ॥১১॥','прабху се парама-вйайӣ ӣш́вара вйабха̄ра
дух̣кхитере ниравадхи дена пураска̄ра',NULL,NULL),('cb.adi.14.12','cb','cb.adi.14','ЧБ Ади 14.12',12,'দুঃখীরে দেখিলে প্রভু বড় দয়া করি’ ।
অন্ন, বস্ত্র, কড়ি-পাতি দেন গৌরহরি ॥১২॥','дух̣кхӣре декхиле прабху бад̣а дайа̄ кари’
анна, вастра, кад̣и-па̄ти дена гаурахари',NULL,NULL),('cb.adi.14.13','cb','cb.adi.14','ЧБ Ади 14.13',13,'নিরবধি অতিথি আইসে প্রভু-ঘরে ।
যার যেন যোগ্য, প্রভু দেন সবাকারে ॥১৩॥','ниравадхи атитхи а̄исе прабху-гхаре
йа̄’ра йена йогйа, прабху дена саба̄каре',NULL,NULL),('cb.adi.14.14','cb','cb.adi.14','ЧБ Ади 14.14',14,'কোনদিন সন্ন্যাসী আইসে দশ বিশ ।
সবা’ নিমন্ত্রেন প্রভু হইয়া হরিষ ॥১৪॥','кона-дина саннйа̄сӣ а̄исе даш́а биш́а
саба̄’ нимантрена прабху хаийа̄ хариш̣а',NULL,NULL),('cb.adi.14.15','cb','cb.adi.14','ЧБ Ади 14.15',15,'সেইক্ষণে কহি’ পাঠায়েন জননীরে ।
কুড়ি সন্ন্যাসীর ভিক্ষা ঝাট করিবারে ॥১৫॥
ঘরে কিছু নাই, আই চিন্তে মনে-মনে ।
‘কুড়ি সন্ন্যাসীর ভিক্ষা হইবে কেমনে?’ ॥১৬॥
চিন্তিতেই হেন, নাহি জানি কোন্ জনে ।
সকল সম্ভার আনি’ দেয় সেইক্ষণে ॥১৭॥','сеи-кш̣ан̣е кахи’ па̄т̣ха̄йена джананӣре
куд̣и саннйа̄сӣра бхикш̣а̄ джха̄т̣а кариба̄ре
гхаре кичху на̄и, а̄и чинте мане-мане
‘куд̣и саннйа̄сӣра бхикш̣а̄ хаибе кемане?’
чинтитеи хӣна, на̄хи джани кон джане
сакала самбха̄ра а̄ни’ дейа сеи-кш̣ан̣е',NULL,NULL),('cb.adi.14.18','cb','cb.adi.14','ЧБ Ади 14.18',18,'তবে লক্ষ্মী-দেবী গিয়া পরম-সন্তোষে ।
রান্ধেন বিশেষ, তবে প্রভু আসি’ বৈসে ॥১৮॥','табе лакш̣мӣ-девӣ гийа̄ парама-сантош̣е
ра̄ндхена виш́еш̣а, табе прабху а̄си’ ваисе',NULL,NULL),('cb.adi.14.19','cb','cb.adi.14','ЧБ Ади 14.19',19,'সন্ন্যাসীগণেরে প্রভু আপনে বসিয়া ।
তুষ্ট করি’ পাঠায়েন ভিক্ষা করাইয়া ॥১৯॥','саннйа̄сӣ-ган̣ере прабху а̄пане васийа̄
туш̣т̣а кари’ па̄т̣ха̄йена бхикш̣а̄ кара̄ийа̄',NULL,NULL),('cb.adi.14.20','cb','cb.adi.14','ЧБ Ади 14.20',20,'এইমত যতেক অতিথি আসি’ হয় ।
সবারেই জিজ্ঞাসা করেন কৃপাময় ॥২০॥','эи-мата йатека атитхи а̄си’ хайа
саба̄реи джиджн̃а̄са̄ карена кр̣па̄майа',NULL,NULL),('cb.adi.14.21','cb','cb.adi.14','ЧБ Ади 14.21',21,'গৃহস্থেরে মহাপ্রভু শিখায়েন ধর্ম্ম ।
“অতিথির সেবা—গৃহস্থের মূলকর্ম্ম ॥২১॥','гр̣хастхере маха̄прабху ш́икха̄йена дхарма
‘атитхира сева— гр̣хастхера мӯла-карма',NULL,NULL),('cb.adi.14.22','cb','cb.adi.14','ЧБ Ади 14.22',22,'গৃহস্থ হইয়া অতিথি-সেবা না করে ।
পশু-পক্ষী হইতে ‘অধম’ বলি তারে ॥২২॥','гр̣хастха хаилйа̄ атитхи-сева на̄ каре
паш́у-пакш̣ӣ хаите ‘адхама’ бали та̄’ре',NULL,NULL),('cb.adi.14.23','cb','cb.adi.14','ЧБ Ади 14.23',23,'যার বা না থাকে কিছু পূর্ব্বাদৃষ্ট-দোষে ।
সেই তৃণ, জল, ভূমি দিবেক সন্তোষে ॥২৩॥','йа̄’ра ва̄ на̄ тха̄ке кичху пӯрва̄др̣ш̣т̣а-дош̣е
сеи, тр̣н̣а, джала, бхӯми дибека сантош̣е',NULL,NULL),('cb.adi.14.24','cb','cb.adi.14','ЧБ Ади 14.24',24,'তৃণানি ভূমিরুদকং বাক্ চতুর্থী চ সুনৃতা ।
এতান্যপি সতাং গেহে নোচ্ছিদ্যন্তে কদাচন ॥২৪॥','тр̣н̣а̄ди бхӯмир удакам̇
ва̄к чатуртхӣ ча ва̄ сунр̣та̄
эта̄нй апи сата̄м̇ гехе
ноччхидйанте када̄чана',NULL,NULL),('cb.adi.14.28','cb','cb.adi.14','ЧБ Ади 14.28',28,'সেই সব অতিথি—পরম-ভাগ্যবান্ ।
লক্ষ্মী-নারায়ণ যারে করে অন্ন দান ॥২৮॥','сеи саба атитхи — парама-бха̄гйава̄н
лакш̣мӣ-на̄ра̄йан̣а йа̄’ре каре анна да̄на',NULL,NULL),('cb.adi.14.29','cb','cb.adi.14','ЧБ Ади 14.29',29,'যার অন্নে ব্রহ্মাদির আশা অনুক্ষণ ।
হেন সে অদ্ভুত, তাহা খায় যে-তে-জন ॥২৯॥','йа̄’ра анне брахма̄дира а̄ш́а̄ анукш̣ан̣а
хӣна се адбхута, та̄ха̄ кха̄йа йе-те джн̃а',NULL,NULL),('cb.adi.14.30','cb','cb.adi.14','ЧБ Ади 14.30',30,'কেহ কেহ ইতোমধ্যে কহে অন্য কথা ।
“সে অন্নের যোগ্য অন্যে না হয় সর্ব্বথা ॥৩০॥
ব্রহ্মা-শিব-শুক-ব্যাস-নারদাদি করি’ ।
সুর-সিদ্ধ-আদি যত স্বচ্ছন্দ-বিহারী ॥৩১॥
লক্ষ্মী-নারায়ণ অবতীর্ণ নবদ্বীপে ।
জানি’ সবে আইসেন ভিক্ষুকের রূপে ॥৩২॥','кеха кеха ито-мадхйе кахе анйа катха̄
‘се аннера йогйа анйе на̄ хайа сарватха̄
брахма̄-ш́ива-ш́ука-вйа̄са-на̄рада̄ди кари’
сура-сиддха-а̄ди йата сваччханда-виха̄рӣ
лакш̣мӣ-на̄ра̄йан̣а аватӣрн̣а навадвӣпе
джа̄ни’ сабе а̄исена бхикш̣укера рӯпе',NULL,NULL),('cb.adi.14.33','cb','cb.adi.14','ЧБ Ади 14.33',33,'অন্যথা সে-স্থানে যাইবার শক্তি কার? ।
ব্রহ্মা-আদি বিনা কি সে অন্ন পায় আর?” ॥৩৩॥','анйатха̄ се-стха̄не йа̄иба̄ра ш́акти ка̄’ра?
брахма̄-а̄ди вина̄ ки се анна па̄йа а̄ра?’',NULL,NULL),('cb.adi.14.34','cb','cb.adi.14','ЧБ Ади 14.34',34,'কেহ বলে,—“দুঃখিতে তারিতে অবতার ।
সর্ব্বমতে দুঃখিতেরে করেন নিস্তার ॥৩৪॥','кеха бале, — ‘дух̣кхите та̄рите авата̄ра
сарва-мате дух̣кхитере карена ниста̄ра',NULL,NULL),('cb.adi.14.40','cb','cb.adi.14','ЧБ Ади 14.40',40,'ঊষঃকাল হৈতে লক্ষ্মী যত গৃহ-কর্ম্ম ।
আপনে করেন সব,—এই তাঁর ধর্ম্ম ॥৪০॥','ӯш̣ах̣-ка̄ла хаите лакш̣мӣ йата гр̣ха-карма
а̄пане карена саба, — эи та̄н̇’ра дхарма',NULL,NULL),('cb.adi.14.41','cb','cb.adi.14','ЧБ Ади 14.41',41,'দেব-গৃহে করেন যে স্বস্তিকমণ্ডলী ।
শঙ্খ-চক্র লিখেন হইয়া কুতূহলী ॥৪১॥','дева-гр̣хе карена йе свастика-ман̣д̣алӣ
ш́ан̇кха-чакра ликхена хаийа̄ кутӯхале',NULL,NULL),('cb.adi.14.42','cb','cb.adi.14','ЧБ Ади 14.42',42,'গন্ধ, পুষ্প, ধূপ, দীপ, সুবাসিত জল ।
ঈশ্বর-পূজার সজ্জা করেন সকল ॥৪২॥','гандха, пуш̣па, дхӯпа, дӣпа, сува̄сита джала
ӣш́вара-пӯджа̄ра саджджа карена сакала',NULL,NULL),('cb.adi.14.43','cb','cb.adi.14','ЧБ Ади 14.43',43,'নিরবধি তুলসীর করেন সেবন ।
ততোঽধিক শচীর সেবায় তাঁর মন ॥৪৩॥','ниравадхи туласӣра карена севана
тато’дхика ш́ачӣра сева̄йа та̄н̇’ра мана',NULL,NULL),('cb.adi.14.44','cb','cb.adi.14','ЧБ Ади 14.44',44,'লক্ষ্মীর চরিত্র দেখি’ শ্রীগৌরসুন্দর ।
মুখে কিছু না বলেন, সন্তোষ অন্তর ॥৪৪॥','лакш̣мӣра чаритра декхи’ ш́рӣ-гаурасундара
мукхе кичху на̄ балена, сантош̣а антара',NULL,NULL),('cb.adi.14.45','cb','cb.adi.14','ЧБ Ади 14.45',45,'কোনদিন লক্ষ্মী লই’ প্রভুর চরণ ।
বসিয়া থাকেন পদ-তলে অনুক্ষণ ॥৪৫॥','кона-дина лакш̣мӣ лаи’ прабхура чаран̣а
васийа̄ тха̄кена пада-тале анукш̣ан̣а',NULL,NULL),('cb.adi.14.46','cb','cb.adi.14','ЧБ Ади 14.46',46,'অদ্ভুত দেখেন শচী পুত্ত্র-পদতলে ।
মহা-জ্যোতির্ম্ময় অগ্নিপুঞ্জশিখা জ্বলে ॥৪৬॥','адбхута декхена ш́ачӣ путра-пада-тале
маха̄-джйотир-майа агни-пун̃джа-ш́икха̄ джвале',NULL,NULL),('cb.adi.14.47','cb','cb.adi.14','ЧБ Ади 14.47',47,'কোনদিন মহা-পদ্মগন্ধ শচী আই ।
ঘরে-দ্বারে সর্ব্বত্র পায়েন, অন্ত নাই ॥৪৭॥','кона-дина маха̄-падма-гандха ш́ачӣ а̄и
гхаре-два̄ре сарватра па̄йена, анта на̄и',NULL,NULL),('cb.adi.14.48','cb','cb.adi.14','ЧБ Ади 14.48',48,'হেনমতে লক্ষ্মী-নারায়ণ নবদ্বীপে ।
কেহ নাহি চিনেন আছেন গূঢ়রূপে ॥৪৮॥','хӣна-мате лакш̣мӣ на̄ра̄йан̣а навадвӣпе
кеха на̄хи чинена а̄чхена гӯд̣ха-рӯпе',NULL,NULL),('cb.adi.14.49','cb','cb.adi.14','ЧБ Ади 14.49',49,'তবে কতদিনে ইচ্ছাময় ভগবান্ ।
বঙ্গদেশ দেখিতে হইল ইচ্ছা তান ॥৪৯॥
তবে প্রভু জননীরে বলিলেন বাণী ।
“কতদিন প্রবাস করিব, মাতা, আমি” ॥৫০॥
লক্ষ্মী-প্রতি কহিলেন শ্রীগৌরসুন্দর ।
“মায়ের সেবন তুমি কর নিরন্তর” ॥৫১॥','табе ката-дине иччха̄-майа бхагава̄н
бан̇га-деш́а декхите хаила иччха̄ та̄’на
